import { MetadataRoute } from 'next'

export default function robots(): MetadataRoute.Robots {
  const baseUrl = process.env.NEXT_PUBLIC_SITE_URL || 'https://maiytechhub.com'
  return {
    rules: [
      {
        userAgent: '*',
        allow: '/',
        disallow: ['/api/', '/admin/'],
      },
    ],
    sitemap: `${baseUrl}/sitemap.xml`,
  }
}

import { MetadataRoute } from 'next'
import { getAllArticles } from '@/lib/content'
import { CATEGORIES, SITE } from '@/config/site'

export default async function sitemap(): Promise<MetadataRoute.Sitemap> {
  const articles = await getAllArticles()

  const articleUrls = articles.map((article) => ({
    url: `${SITE.url}/articles/${article.slug}`,
    lastModified: new Date(article.publishedAt),
    changeFrequency: 'monthly' as const,
    priority: 0.8,
  }))

  const categoryUrls = CATEGORIES.map((cat) => ({
    url: `${SITE.url}/articles/category/${cat.slug}`,
    lastModified: new Date(),
    changeFrequency: 'weekly' as const,
    priority: 0.7,
  }))

  return [
    {
      url: SITE.url,
      lastModified: new Date(),
      changeFrequency: 'daily',
      priority: 1,
    },
    {
      url: `${SITE.url}/articles`,
      lastModified: new Date(),
      changeFrequency: 'daily',
      priority: 0.9,
    },
    {
      url: `${SITE.url}/music`,
      lastModified: new Date(),
      changeFrequency: 'monthly',
      priority: 0.6,
    },
    {
      url: `${SITE.url}/study`,
      lastModified: new Date(),
      changeFrequency: 'monthly',
      priority: 0.6,
    },
    {
      url: `${SITE.url}/about`,
      lastModified: new Date(),
      changeFrequency: 'yearly',
      priority: 0.5,
    },
    ...categoryUrls,
    ...articleUrls,
  ]
}

import { SITE } from '@/config/site'

export function WebSiteSchema() {
  const schema = {
    '@context': 'https://schema.org',
    '@type': 'WebSite',
    name: SITE.name,
    url: SITE.url,
    description: SITE.description,
    potentialAction: {
      '@type': 'SearchAction',
      target: {
        '@type': 'EntryPoint',
        urlTemplate: `${SITE.url}/search?q={search_term_string}`,
      },
      'query-input': 'required name=search_term_string',
    },
    publisher: {
      '@type': 'Organization',
      name: SITE.name,
      url: SITE.url,
    },
  }
  return (
    <script
      type="application/ld+json"
      dangerouslySetInnerHTML={{ __html: JSON.stringify(schema) }}
    />
  )
}

import { SITE } from '@/config/site'

export function ArticleSchema({ article }: {
  article: {
    slug: string
    title: string
    excerpt: string
    category: string
    tags: string[]
    hero?: string | null
    author: string
    readingTime: number
    publishedAt: string
  }
}) {
  const schema = {
    '@context': 'https://schema.org',
    '@type': 'Article',
    headline: article.title,
    description: article.excerpt,
    image: article.hero,
    author: {
      '@type': 'Person',
      name: article.author,
      url: `${SITE.url}/about`,
    },
    publisher: {
      '@type': 'Organization',
      name: SITE.name,
      url: SITE.url,
    },
    datePublished: article.publishedAt,
    mainEntityOfPage: {
      '@type': 'WebPage',
      '@id': `${SITE.url}/articles/${article.slug}`,
    },
    wordCount: article.readingTime * 200, // rough estimate
    timeRequired: `PT${article.readingTime}M`,
  }

  return (
    <script
      type="application/ld+json"
      dangerouslySetInnerHTML={{ __html: JSON.stringify(schema) }}
    />
  )
}

import { SITE } from '@/config/site'

interface BreadcrumbItem {
  label: string
  href: string
}

export function BreadcrumbSchema({ items }: { items: BreadcrumbItem[] }) {
  const schema = {
    '@context': 'https://schema.org',
    '@type': 'BreadcrumbList',
    itemListElement: [
      {
        '@type': 'ListItem',
        position: 1,
        name: 'Trang chủ',
        item: SITE.url,
      },
      ...items.map((item, i) => ({
        '@type': 'ListItem',
        position: i + 2,
        name: item.label,
        item: `${SITE.url}${item.href}`,
      })),
    ],
  }
  return (
    <script
      type="application/ld+json"
      dangerouslySetInnerHTML={{ __html: JSON.stringify(schema) }}
    />
  )
}

import { notFound } from 'next/navigation'
import Link from 'next/link'
import { Clock, Calendar, ArrowLeft, BookOpen } from 'lucide-react'
import { compileMDX } from 'next-mdx-remote/rsc'
import remarkGfm from 'remark-gfm'
import rehypeSlug from 'rehype-slug'
import rehypeAutolinkHeadings from 'rehype-autolink-headings'
import rehypeHighlight from 'rehype-highlight'
import { getArticleBySlug, getAllSlugs, getArticlesByCategory } from '@/lib/content'
import { ArticleCard } from '@/components/blog/article-card'
import { Breadcrumbs } from '@/components/seo/breadcrumbs'
import { ArticleSchema } from '@/components/seo/article-schema'
import { ReadingProgress } from '@/components/blog/reading-progress'
import { SocialShare } from '@/components/blog/social-share'
import { TableOfContents } from '@/components/blog/toc'
import { TrackerWrapper } from '@/components/blog/tracker-wrapper'

export const dynamic = 'force-static'

interface Props {
  params: { slug: string }
}

export async function generateStaticParams() {
  const slugs = await getAllSlugs()
  return slugs.map((slug) => ({ slug }))
}

export async function generateMetadata({ params }: Props) {
  const article = await getArticleBySlug(params.slug)
  if (!article) return { title: 'Không tìm thấy' }
  return {
    title: article.title,
    description: article.excerpt,
    openGraph: {
      type: 'article',
      title: article.title,
      description: article.excerpt,
      images: article.hero ? [{ url: article.hero }] : [],
      publishedTime: article.publishedAt,
    },
  }
}

// ── MDX components ───────────────────────────────────────────────────────────
const mdxComponents = {
  // Inline code
  code: ({ children, className, ...p }: any) => {
    if (className) return <>{children}</>
    return (
      <code className="px-1.5 py-0.5 rounded bg-muted text-sm font-mono text-primary/90">
        {children}
      </code>
    )
  },
  a: ({ children, href, ...p }: any) => (
    <a
      href={href}
      className="text-primary underline-offset-4 hover:underline"
      target={href?.startsWith('http') ? '_blank' : undefined}
      rel={href?.startsWith('http') ? 'noopener noreferrer' : undefined}
      {...p}
    >
      {children}
    </a>
  ),
  h2: ({ children, id, ...p }: any) => (
    <h2 id={id} className="scroll-mt-24 font-bold text-2xl mt-10 mb-4" {...p}>
      {children}
    </h2>
  ),
  h3: ({ children, id, ...p }: any) => (
    <h3 id={id} className="scroll-mt-24 font-bold text-xl mt-8 mb-3" {...p}>
      {children}
    </h3>
  ),
  table: ({ children, ...p }: any) => (
    <div className="overflow-x-auto my-6">
      <table className="w-full border-collapse border border-border text-sm" {...p}>
        {children}
      </table>
    </div>
  ),
  th: ({ children, ...p }: any) => (
    <th className="border border-border bg-muted px-4 py-2 text-left font-semibold" {...p}>
      {children}
    </th>
  ),
  td: ({ children, ...p }: any) => (
    <td className="border border-border px-4 py-2" {...p}>
      {children}
    </td>
  ),
}

export default async function ArticlePage({ params }: Props) {
  const article = await getArticleBySlug(params.slug)
  if (!article) notFound()

  const related = (await getArticlesByCategory(article.category))
    .filter((a) => a.slug !== params.slug)
    .slice(0, 3)

  const publishDate = new Date(article.publishedAt).toLocaleDateString('vi-VN', {
    day: 'numeric',
    month: 'long',
    year: 'numeric',
  })

  // @ts-ignore
  const result = await compileMDX({
    source: article.content,
    options: {
      mdxOptions: {
        remarkPlugins: [remarkGfm],
        rehypePlugins: [
          rehypeSlug,
          [rehypeAutolinkHeadings, { behavior: 'wrap' }],
          rehypeHighlight,
        ],
      },
    },
    components: mdxComponents,
  })
  const content = result.content

  return (
    <>
      <TrackerWrapper slug={params.slug} />
      <ArticleSchema article={article} />
      <ReadingProgress />

      <div className="container py-8">
        <Breadcrumbs
          items={[
            { label: 'Trang chủ', href: '/' },
            { label: 'Bài viết', href: '/articles' },
            { label: article.category, href: `/articles/category/${article.category}` },
            { label: article.title },
          ]}
        />

        <div className="flex gap-12 max-w-5xl mx-auto">
          <article className="flex-1 min-w-0" data-article-content>
            {/* Back */}
            <Link
              href="/articles"
              className="inline-flex items-center gap-1 text-sm text-muted-foreground hover:text-primary mb-6 transition-colors"
            >
              <ArrowLeft className="h-4 w-4" /> Quay lại bài viết
            </Link>

            {/* Header */}
            <header className="mb-8">
              <div className="flex items-center gap-3 mb-4">
                <span className="px-3 py-1 text-xs font-medium rounded-full bg-primary/10 text-primary">
                  {article.category}
                </span>
                <span className="flex items-center gap-1 text-sm text-muted-foreground">
                  <Clock className="h-4 w-4" />
                  {article.readingTime} phút đọc
                </span>
              </div>

              <h1 className="text-3xl md:text-4xl font-bold tracking-tight mb-4">
                {article.title}
              </h1>

              <p className="text-lg text-muted-foreground mb-6">{article.excerpt}</p>

              <div className="flex items-center gap-4 text-sm text-muted-foreground border-y border-border/40 py-3">
                <span className="flex items-center gap-1.5">
                  <BookOpen className="h-4 w-4" />
                  {article.author}
                </span>
                <span className="flex items-center gap-1.5">
                  <Calendar className="h-4 w-4" />
                  {publishDate}
                </span>
                <div className="ml-auto">
                  <SocialShare title={article.title} />
                </div>
              </div>
            </header>

            {/* Hero */}
            {article.hero && (
              // eslint-disable-next-line @next/next/no-img-element
              <img
                src={article.hero}
                alt={article.title}
                className="w-full rounded-xl mb-8 aspect-video object-cover"
              />
            )}

            {/* Tags */}
            {article.tags.length > 0 && (
              <div className="flex flex-wrap gap-2 mb-8">
                {article.tags.map((tag) => (
                  <Link
                    key={tag}
                    href={`/search?q=${tag}`}
                    className="px-3 py-1 text-xs rounded-full border border-border hover:border-primary/50 hover:bg-primary/5 transition-all"
                  >
                    #{tag}
                  </Link>
                ))}
              </div>
            )}

            {/* MDX Content */}
            <div className="prose-custom">{content}</div>

            {/* Share */}
            <div className="mt-12 pt-8 border-t border-border/40 flex items-center justify-between">
              <p className="text-sm text-muted-foreground">
                Nếu thấy hữu ích, hãy chia sẻ bài viết này nhé!
              </p>
              <SocialShare title={article.title} />
            </div>
          </article>

          {/* TOC */}
          <aside className="hidden xl:block w-56 flex-shrink-0">
            <div className="sticky top-24">
              <TableOfContents />
            </div>
          </aside>
        </div>

        {related.length > 0 && (
          <section className="max-w-3xl mx-auto mt-16">
            <h2 className="text-xl font-bold mb-6">Bài viết liên quan</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {related.map((a) => (
                <ArticleCard key={a.slug} article={a} />
              ))}
            </div>
          </section>
        )}
      </div>
    </>
  )
}

import { Metadata } from 'next'
import { notFound } from 'next/navigation'
import { CATEGORIES } from '@/config/site'
import { getArticlesByCategory, getAllSlugs } from '@/lib/content'
import { ArticleCard } from '@/components/blog/article-card'
import { Breadcrumbs } from '@/components/seo/breadcrumbs'

interface Props {
  params: { slug: string }
}

export async function generateStaticParams() {
  return CATEGORIES.map((c) => ({ slug: c.slug }))
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const cat = CATEGORIES.find((c) => c.slug === params.slug)
  if (!cat) return {}
  return {
    title: `${cat.label} — Bài viết`,
    description: cat.description,
  }
}

export default async function CategoryPage({ params }: Props) {
  const cat = CATEGORIES.find((c) => c.slug === params.slug)
  if (!cat) notFound()

  const articles = await getArticlesByCategory(params.slug)

  return (
    <div className="container py-8">
      <Breadcrumbs
        items={[
          { label: 'Trang chủ', href: '/' },
          { label: 'Bài viết', href: '/articles' },
          { label: cat.label },
        ]}
      />

      <div className="mb-10">
        <h1 className="text-3xl font-bold mb-2">{cat.label}</h1>
        <p className="text-muted-foreground">{cat.description}</p>
      </div>

      {articles.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {articles.map((article) => (
            <ArticleCard key={article.slug} article={article} />
          ))}
        </div>
      ) : (
        <div className="text-center py-20 text-muted-foreground">
          <p className="text-lg mb-2">Chưa có bài viết nào trong chủ đề này.</p>
          <p className="text-sm"> Quay lại <a href="/articles" className="text-primary hover:underline">danh sách bài viết</a>.</p>
        </div>
      )}
    </div>
  )
}

import { Metadata } from 'next'
import { getAllArticles } from '@/lib/content'
import { ArticlesFilter } from '@/components/blog/articles-filter'

export const metadata: Metadata = {
  title: 'Tất cả bài viết',
  description: 'Tất cả bài viết về CTDL & Giải thuật, AI, Web Dev, DevOps và CS Fundamentals.',
}

export default async function ArticlesPage() {
  const articles = await getAllArticles()

  return (
    <div className="container py-12">
      <div className="mb-8">
        <h1 className="text-3xl font-bold mb-3">Tất cả bài viết</h1>
        <p className="text-muted-foreground">
          {articles.length} bài viết về CNTT — từ cơ bản đến nâng cao
        </p>
      </div>

      <ArticlesFilter articles={articles} />
    </div>
  )
}

import Link from 'next/link'
import { ChevronRight, Home } from 'lucide-react'

interface BreadcrumbItem {
  label: string
  href?: string
}

interface BreadcrumbsProps {
  items: BreadcrumbItem[]
}

export function Breadcrumbs({ items }: BreadcrumbsProps) {
  return (
    <nav aria-label="Breadcrumb" className="mb-6">
      <ol className="flex items-center gap-1 text-sm text-muted-foreground flex-wrap">
        <li>
          <Link href="/" className="hover:text-primary transition-colors">
            <Home className="h-4 w-4" />
          </Link>
        </li>
        {items.map((item, i) => (
          <li key={i} className="flex items-center gap-1">
            <ChevronRight className="h-3 w-3" />
            {item.href ? (
              <Link
                href={item.href}
                className="hover:text-primary transition-colors capitalize"
              >
                {item.label}
              </Link>
            ) : (
              <span className="text-foreground capitalize truncate max-w-[200px]">
                {item.label}
              </span>
            )}
          </li>
        ))}
      </ol>
    </nav>
  )
}

import Link from 'next/link'
import { Clock, ArrowRight, Star } from 'lucide-react'
import { CATEGORIES } from '@/config/site'

export interface ArticleSummary {
  slug: string
  title: string
  excerpt: string
  category: string
  tags: string[]
  hero?: string | null
  author: string
  readingTime: number
  publishedAt: string
}

interface ArticleCardProps {
  article: ArticleSummary
  variant?: 'default' | 'compact'
  featured?: boolean
  index?: number
}

export function ArticleCard({ article, variant = 'default', featured = false, index = 0 }: ArticleCardProps) {
  const cat = CATEGORIES.find((c) => c.slug === article.category)

  if (variant === 'compact') {
    return (
      <Link
        href={`/articles/${article.slug}`}
        className="article-card flex items-start gap-3 p-3 rounded-xl border border-transparent hover:border-border hover:bg-muted/50 transition-all duration-300 group"
      >
        {article.hero && (
          // eslint-disable-next-line @next/next/no-img-element
          <img
            src={article.hero}
            alt={article.title}
            className="article-card-img w-16 h-16 rounded-xl object-cover flex-shrink-0"
          />
        )}
        <div className="min-w-0">
          {cat && (
            <p className="text-xs font-semibold mb-1" style={{ color: cat.color.replace('bg-', '') }}>
              {cat.labelShort}
            </p>
          )}
          <h3 className="text-sm font-medium line-clamp-2 group-hover:text-primary transition-colors duration-200">
            {article.title}
          </h3>
        </div>
      </Link>
