export const metadata: Metadata = {
  title: 'Premium',
  description: 'Khoá học và bài viết nâng cao dành cho thành viên Premium MAIY Tech Hub.',
}

export default function PremiumLayout({ children }: { children: React.ReactNode }) {
  return <>{children}</>
}

'use client'

import { useState } from 'react'
import { Play, Pause, SkipForward, Headphones, Target, Moon, Zap, BookOpen, Music2, Sparkles, ListMusic } from 'lucide-react'
import { useMusic, type Track } from '@/providers/music-provider'
import { SectionParticles } from '@/components/shared/section-particles'

const MOODS = [
  { id: 'focus', label: 'Focus', Sub: 'Tập trung', Icon: Target, gradient: 'from-blue-600/20 to-indigo-600/10 border-blue-500/20 hover:border-blue-400/50', active: 'bg-blue-600 text-white shadow-lg shadow-blue-600/30', glow: '#3b82f6' },
  { id: 'sleep', label: 'Sleep', Sub: 'Ngủ ngon', Icon: Moon, gradient: 'from-violet-600/20 to-purple-600/10 border-violet-500/20 hover:border-violet-400/50', active: 'bg-violet-600 text-white shadow-lg shadow-violet-600/30', glow: '#7c3aed' },
  { id: 'energize', label: 'Energize', Sub: 'Năng lượng', Icon: Zap, gradient: 'from-amber-500/20 to-orange-600/10 border-amber-500/20 hover:border-amber-400/50', active: 'bg-amber-500 text-white shadow-lg shadow-amber-500/30', glow: '#f59e0b' },
  { id: 'study', label: 'Study', Sub: 'Học bài', Icon: BookOpen, gradient: 'from-emerald-600/20 to-green-600/10 border-emerald-500/20 hover:border-emerald-400/50', active: 'bg-emerald-600 text-white shadow-lg shadow-emerald-600/30', glow: '#059669' },
] as const

const PLAYLISTS: Record<string, Track[]> = {
