                      <mood.Icon className={`h-4 w-4 ${isActive ? '' : 'text-muted-foreground'}`} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className={`text-sm font-semibold ${isActive ? '' : 'group-hover:text-foreground'} transition-colors`}>
                        {mood.label}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        {tracks.length} tracks · {hours > 0 ? `${hours}h ` : ''}{mins}m
                      </p>
                    </div>
                  </button>
                )
              })}
            </div>

            {/* Stats */}
            <div className="rounded-2xl border border-white/[0.06] bg-white/[0.01] p-5">
              <h3 className="text-xs font-bold uppercase tracking-widest text-muted-foreground mb-4">
                Thư viện của bạn
              </h3>
              <div className="space-y-3">
                {[
                  { label: 'Tổng tracks', value: Object.values(PLAYLISTS).flat().length, Icon: Music2 },
                  { label: 'Playlists', value: MOODS.length, Icon: ListMusic },
                  { label: 'Giờ nhạc', value: `${Math.floor(Object.values(PLAYLISTS).flat().reduce((s, t) => s + t.duration, 0) / 3600)}h`, Icon: Sparkles },
                ].map((stat) => (
                  <div key={stat.label} className="flex items-center justify-between">
                    <div className="flex items-center gap-2 text-muted-foreground">
                      <stat.Icon className="h-4 w-4" />
                      <span className="text-sm">{stat.label}</span>
                    </div>
                    <span className="text-sm font-bold">{stat.value}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Tip */}
            <div className="mt-4 p-4 rounded-xl bg-violet-500/5 border border-violet-500/10">
              <p className="text-xs text-muted-foreground leading-relaxed">
                💡 <strong className="text-foreground">Mini-player</strong> hoạt động xuyên suốt mọi trang. Bật nhạc ở đây và tiếp tục đọc bài viết!
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

