export const metadata: Metadata = {
  title: 'Tags',
  description: 'Tất cả tags trên MAIY Tech Hub.',
}

export default async function TagsPage() {
  const articles = await getAllArticles()

  const tagMap = new Map<string, number>()
  articles.forEach((a) => {
    a.tags.forEach((tag) => {
      tagMap.set(tag, (tagMap.get(tag) || 0) + 1)
    })
  })

  const tags = Array.from(tagMap.entries()).sort((a, b) => b[1] - a[1])

  const tagColors = [
    { bg: 'hover:bg-blue-500/20', border: 'border-blue-500/25', text: 'text-blue-400', icon: '#3b82f6', glow: 'shadow-blue-500/20', gradient: 'from-blue-600/10 to-transparent' },
    { bg: 'hover:bg-violet-500/20', border: 'border-violet-500/25', text: 'text-violet-400', icon: '#7c3aed', glow: 'shadow-violet-500/20', gradient: 'from-violet-600/10 to-transparent' },
    { bg: 'hover:bg-emerald-500/20', border: 'border-emerald-500/25', text: 'text-emerald-400', icon: '#10b981', glow: 'shadow-emerald-500/20', gradient: 'from-emerald-600/10 to-transparent' },
    { bg: 'hover:bg-amber-500/20', border: 'border-amber-500/25', text: 'text-amber-400', icon: '#f59e0b', glow: 'shadow-amber-500/20', gradient: 'from-amber-600/10 to-transparent' },
    { bg: 'hover:bg-pink-500/20', border: 'border-pink-500/25', text: 'text-pink-400', icon: '#ec4899', glow: 'shadow-pink-500/20', gradient: 'from-pink-600/10 to-transparent' },
    { bg: 'hover:bg-cyan-500/20', border: 'border-cyan-500/25', text: 'text-cyan-400', icon: '#06b6d4', glow: 'shadow-cyan-500/20', gradient: 'from-cyan-600/10 to-transparent' },
    { bg: 'hover:bg-red-500/20', border: 'border-red-500/25', text: 'text-red-400', icon: '#ef4444', glow: 'shadow-red-500/20', gradient: 'from-red-600/10 to-transparent' },
    { bg: 'hover:bg-orange-500/20', border: 'border-orange-500/25', text: 'text-orange-400', icon: '#f97316', glow: 'shadow-orange-500/20', gradient: 'from-orange-600/10 to-transparent' },
  ]

  return (
    <div className="min-h-screen">
      {/* Clean subtle background — no heavy blur orbs */}
      <div className="fixed inset-0 pointer-events-none -z-10">
        <div className="absolute inset-0 bg-[#09090b]" />
        {/* Single faint gradient accent */}
        <div className="absolute top-0 right-0 w-[600px] h-[400px] rounded-full bg-violet-600/[0.04] blur-[100px]" />
        <div className="absolute bottom-1/4 left-0 w-[400px] h-[300px] rounded-full bg-blue-600/[0.03] blur-[80px]" />
      </div>

      {/* Header */}
      <section className="relative py-20 px-6 md:px-12 overflow-hidden">
        <div className="max-w-5xl mx-auto">
          {/* Section label */}
          <div className="flex items-center gap-3 mb-5">
            <div className="w-11 h-11 rounded-full bg-gradient-to-br from-violet-500 to-blue-500 flex items-center justify-center shadow-lg shadow-violet-500/25">
              <Hash className="h-5 w-5 text-white" />
            </div>
            <span className="text-xs font-bold uppercase tracking-[0.2em] text-white/20">
              Khám phá
            </span>
          </div>

          {/* Heading */}
          <h1 className="text-5xl md:text-6xl font-black tracking-tight mb-4">
            <span className="bg-gradient-to-r from-violet-300 via-purple-300 to-blue-300 bg-clip-text text-transparent">
              Tags
            </span>
          </h1>

          {/* Stats */}
          <p className="text-white/30 text-base">
            {tags.length} tags · {articles.length} bài viết
          </p>
        </div>
      </section>

      {/* Tag cloud */}
      <section className="px-6 md:px-12 pb-10">
        <div className="max-w-5xl mx-auto">
          {/* Section divider */}
          <div className="flex items-center gap-3 mb-6">
            <div className="w-1 h-6 rounded-full bg-gradient-to-b from-violet-500 to-blue-500" />
            <h2 className="text-sm font-bold uppercase tracking-[0.15em] text-white/40">
              Tất cả tags
            </h2>
          </div>

          <div className="flex flex-wrap gap-3">
            {tags.map(([tag, count], i) => {
              const color = tagColors[i % tagColors.length]
              return (
                <Link
                  key={tag}
                  href={`/search?q=${encodeURIComponent(tag)}`}
                  className={`
                    group relative inline-flex items-center gap-2.5 px-5 py-3 rounded-2xl
                    border backdrop-blur-sm
                    transition-all duration-300 hover:-translate-y-1
                    hover:shadow-xl ${color.glow}
                    ${color.border}
                    bg-black/20 hover:bg-black/40
                  `}
                >
                  <Tag
                    className="h-4 w-4 transition-transform duration-300 group-hover:scale-110"
                    style={{ color: color.icon }}
                  />
                  <span className="text-sm font-semibold" style={{ color: color.icon }}>
                    {tag}
                  </span>
                  <span
                    className="px-2 py-0.5 rounded-full text-[10px] font-black"
                    style={{ backgroundColor: color.icon + '15', color: color.icon }}
                  >
                    {count}
                  </span>
                </Link>
              )
            })}
          </div>
        </div>
      </section>

      {/* Popular tags — clean card grid */}
      {tags.length > 0 && (
        <section className="px-6 md:px-12 pb-20">
          <div className="max-w-5xl mx-auto">
            {/* Section divider */}
            <div className="flex items-center gap-3 mb-6">
              <div className="w-1 h-6 rounded-full bg-gradient-to-b from-pink-500 to-rose-500" />
              <h2 className="text-sm font-bold uppercase tracking-[0.15em] text-white/40">
                Phổ biến nhất
              </h2>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {tags.slice(0, 9).map(([tag, count], i) => {
                const color = tagColors[i % tagColors.length]
                return (
                  <Link
                    key={tag}
                    href={`/search?q=${encodeURIComponent(tag)}`}
                    className={`
                      group relative flex items-center justify-between p-5 rounded-2xl
                      border backdrop-blur-sm
                      transition-all duration-300 hover:-translate-y-1.5 hover:shadow-xl
                      ${color.border} ${color.glow}
                      bg-black/20 hover:bg-black/40
                    `}
                  >
                    <div className="flex items-center gap-4 relative">
                      <div
                        className="w-12 h-12 rounded-2xl flex items-center justify-center backdrop-blur-sm flex-shrink-0"
                        style={{ backgroundColor: color.icon + '15', border: `1px solid ${color.icon}30` }}
                      >
                        <Tag className="h-5 w-5" style={{ color: color.icon }} />
                      </div>
                      <div>
                        <p className="font-bold text-sm" style={{ color: color.icon }}>{tag}</p>
                        <p className="text-xs text-white/30">{count} bài viết</p>
                      </div>
                    </div>

                    <div
                      className="w-9 h-9 rounded-full flex items-center justify-center text-xs font-black flex-shrink-0"
                      style={{ backgroundColor: color.icon + '12', color: color.icon, border: `1px solid ${color.icon}20` }}
                    >
                      {i + 1}
                    </div>
                  </Link>
                )
              })}
            </div>
          </div>
        </section>
      )}

      {/* Empty state */}
      {tags.length === 0 && (
        <div className="px-6 pb-20 text-center">
          <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-white/[0.02] border border-white/[0.06] mb-6">
            <Tag className="h-10 w-10 text-white/[0.08]" />
          </div>
          <p className="text-white/20 text-lg font-medium mb-2">Chưa có tags nào</p>
          <p className="text-white/10 text-sm">Bài viết đầu tiên sẽ tạo tags tự động.</p>
        </div>
      )}
    </div>
  )
}

